package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        CSVFormat result = format.withFirstRecordAsHeader();

        assertNotNull(result);
        // It should have header set (non-null)
        assertNotNull(result.getHeader());
        // It should skip header record
        assertTrue(result.getSkipHeaderRecord());
        // The returned instance should not be the same as original (immutable pattern)
        assertNotSame(format, result);
    }
}
